/// <summary>
/// assigns value to ItemId and FromBatch field of ETGBin2BinTransferHistory
/// </summary>        
public void create(boolean _append = false)
{
    super(_append);

    ETGBinJournalLine       ETGBinJournalLine;

    select ETGBinJournalLine where ETGBinJournalLine.RecId == ETGBin2BinTransferHistory.BinJournalLine;

    ETGBin2BinTransferHistory.ItemId = ETGBinJournalLine.ItemId;
    ETGBin2BinTransferHistory.FromBatch = ETGBinJournalLine.ToBatch;
}

/// <summary>
/// validate if fromBatch and To batch are properly updated or not.
/// </summary>
public boolean validateWrite()
{
    boolean ret;

    ret = super();

    ETGBinJournalLine       ETGBinJournalLine;

    select ETGBinJournalLine 
        where ETGBinJournalLine.RecId == ETGBin2BinTransferHistory.BinJournalLine
        && ETGBinJournalLine.JournalId == ETGBin2BinTransferHistory.JournalId;

    if (ETGBin2BinTransferHistory.FromBatch != ETGBinJournalLine.ToBatch
        && ETGBin2BinTransferHistory.ToBatch != ETGBinJournalLine.ToBatch)
    {
        ret = checkFailed('@ETGReport:FrombatchAndToBatchValidation');
    }

    return ret;
}

/// <summary>
/// enable or disable controls/datasources
/// </summary>
public int active()
{
    int ret;

    ret = super();

    ETGBin2BinTransferHistory_ds.allowEdit(ETGBin2BinTransferHistory.TransferJRNId == '');
    ETGBin2BinTransferHistory_ds.allowDelete(ETGBin2BinTransferHistory.TransferJRNId == '');

    ETGBinJournalLine       ETGBinJournalLine;

    select ETGBinJournalLine where ETGBinJournalLine.RecId == ETGBin2BinTransferHistory.BinJournalLine;

    if(ETGBinJournalLine.RecId && ETGBinJournalLine.BinFGRNLocked == NoYes::Yes)
    {
        ETGBin2BinTransferHistory_ds.allowCreate(false);
    }

    return ret;
}

/// <summary>
/// creates bin to bin transfer journal.
/// </summary>
public void clicked()
{
    ETGBin2BinTransferHistory       ETGBin2BinTransferHistoryloop;
    InventJournalId  TransferId;
    int loopcount=0,loopcountcheck=0;


    if(InventParameters::find().ETGBin2BinTransferJrnName == '')
    {
        throw error(strFmt('%1','@ETGReport:DefineJournalNameInInventoryParameters'));
    }

    for(ETGBin2BinTransferHistoryloop = getFirstSelection(ETGBin2BinTransferHistory_ds); ETGBin2BinTransferHistoryloop;
    ETGBin2BinTransferHistoryloop = ETGBin2BinTransferHistory_ds.getNext())
    {
        if(ETGBin2BinTransferHistoryloop.FromBatch == ETGBin2BinTransferHistoryloop.ToBatch)
        {
            error(strFmt('%1','@ETGReport:FromBatchandToBatchCannotbeSame'));
            loopcountcheck++;
        }
    }

    if(loopcountcheck >0)
    {
        throw error(strFmt('%1','@ETGReport:ValidationFailed'));
    }


    super();

    for(ETGBin2BinTransferHistoryloop = getFirstSelection(ETGBin2BinTransferHistory_ds); ETGBin2BinTransferHistoryloop;
                    ETGBin2BinTransferHistoryloop = ETGBin2BinTransferHistory_ds.getNext())
    {
        if(ETGBin2BinTransferHistoryloop.TransferJRNId == '')
        {
            loopcount++;
            if(loopcount ==1)
            {
                TransferId =  ETGGlobal::CreateTransferJournalHeaderB2B(ETGBin2BinTransferHistoryloop.RecId);
            }
            ETGGlobal::CreateTransferJournalB2B(ETGBin2BinTransferHistoryloop.RecId,loopcount,TransferId);
        }
    }

    if(TransferId)
    {
        Info(strFmt('@ETGReport:B2BTranferJournalCreationInfo',TransferId));
    }
    ETGBin2BinTransferHistory_ds.research(true);
}
